const contactos = connections
  .filter(c => (c.memberships || []).some(m => (m.contactGroupMembership?.contactGroupResourceName || '').includes('contactGroups')))
  .map(c => ({
    nombre: c.names?.[0]?.displayName || c.names?.[0]?.givenName || '',
    telefono: c.phoneNumbers?.[0]?.value || '',
    resourceName: c.resourceName || '',
    etag: c.etag || ''
  }))
  .filter(c => c.resourceName && (c.nombre || c.telefono));
console.log('SYNC GOOGLE: contactos=' + contactos.length);
return contactos.map(c => ({ json: c }));

const updated = $input.all().filter(i => i.json && i.json.contact_id);
console.log('SYNC GOOGLE -> DB: actualizados=' + updated.length);
return [{ json: { ok: true, actualizados: updated.length } }];

const body = $input.first().json.body || {};
const contactId = String(body.contactId || '').trim();
const nombre = String(body.nombre || '').trim();
const telefono = String(body.telefono || '').trim();
const valid = contactId.length > 0 && (nombre.length > 0 || telefono.length > 0);
const esc = v => String(v).replace(/'/g, "''");
return [{ json: { valid, contactId, nombre, telefono, sql: { contactId: esc(contactId), nombre: esc(nombre), telefono: esc(telefono) } } }];

const input = $('Validar Actualizacion').first().json;
const db = $input.first().json;
const googleResourceName = db.google_resource_name || null;
const etag = db.google_etag || '*';
const nombreFinal = input.nombre || db.nombre || '';
const telefonoFinal = input.telefono || db.telefono || '';
return [{ json: { ...input, googleResourceName, etag, nombreFinal, telefonoFinal, existe: !!googleResourceName } }];

const body = $input.first().json.body || {};
const contactId = String(body.contactId || '').trim();
const mediaUrl  = String(body.mediaUrl  || '').trim();
const mediaType = String(body.mediaType || 'file').trim();
const fileName  = String(body.fileName  || '').trim().slice(0, 200);
const mimeType  = String(body.mimeType  || 'application/octet-stream').trim().slice(0, 120);
const userName  = String(body.userName  || 'Administrador CRM').trim().slice(0, 120);
const validId  = /^[A-Za-z0-9_-]{1,128}$/.test(contactId);
const validUrl = /^https?:\/\/.+/i.test(mediaUrl);
if (!validId || !validUrl) {
  return [{ json: { ok: false, status: 400, error: 'Payload invalido (contactId/mediaUrl)' } }];
}
return [{ json: { ok: true, contactId, mediaUrl, mediaType, fileName, mimeType, userName } }];

const input = $input.first().json;
const contactId = String(input.query?.contactId || '').trim();
const page = Math.min(Math.max(Number(input.query?.page || 1), 1), 100000);
const limit = 50;
const valid = /^[A-Za-z0-9_-]{1,128}$/.test(contactId);
return [{ json: { valid, contactId, page, limit, offset: (page - 1) * limit } }];

const request = $('Preparar Consulta Chat').first().json;
const raw = $input.first().json || {};
const source = raw.messages?.messages || raw.messages || raw.data || [];
const messages = source.map((message) => {
  const direction = String(message.direction || message.messageDirection || '').toLowerCase();
  const appId = String(message.appId || message.app_id || '');
  const attachment = message.attachments?.[0] || message.mediaUrl || message.fileUrl || null;
  return {
    id: String(message.id || message.messageId || (message.dateAdded + '-' + direction)),
    role: direction === 'inbound' ? 'user' : 'assistant',
    senderType: direction === 'inbound' ? 'client' : (appId === '6a150c338ae75824fa553336' ? 'bot' : 'human'),
    text: String(message.body || message.message || message.text || message.content || '').trim(),
    mediaUrl: attachment,
    createdAt: message.dateAdded || message.createdAt || new Date().toISOString(),
    appId,
    ghlMessageId: String(message.id || message.messageId || ''),
    isRead: true,
  };
}).filter((m) => m.text || m.mediaUrl).reverse();
return [{ json: { ok: true, contactId: request.contactId, page: request.page, messages } }];

const input = $input.first().json;
const contactId = String(input.query?.contactId || '').trim();
const cursor = Math.max(Number(input.query?.cursor || 0), 0);
const valid = /^[A-Za-z0-9_-]{1,128}$/.test(contactId) && Number.isSafeInteger(cursor);
return [{ json: { valid, contactId, cursor } }];

const request = $('Preparar Sync CRM').first().json;
const messages = $input.all().map(item => item.json).filter(item => item && item.id);
const nextCursor = messages.length ? messages[messages.length - 1].id : String(request.cursor);
return [{ json: { ok: true, contactId: request.contactId, cursor: nextCursor, messages } }];

const input = $input.first().json;
const body = input.body || {};
const contactId = String(body.contactId || '').trim();
const text = String(body.text || '').trim().slice(0, 4000);
const userName = String(body.userName || 'Administrador CRM').trim().slice(0, 120);
const valid = /^[A-Za-z0-9_-]{1,128}$/.test(contactId) && text.length > 0;
const esc = (v) => String(v).replace(/'/g, "''");
return [{ json: { valid, contactId, text, userName, sql: { contactId: esc(contactId), text: esc(text), userName: esc(userName) } } }];
